    useEffect(() => {
        const fetchAndSubscribe = async () => {
            const initialMessages = await getChatMessages();
            setChatMessages(initialMessages);

            if (isUsingMockData()) return;

            const supabase = getSupabase();
            if (supabase) {
                const channel = supabase.channel('public:chat_messages')
                    .on('postgres_changes', { event: '*', schema: 'public', table: 'chat_messages' }, (payload) => {
                        if (payload.eventType === 'INSERT') {
                            const newMessageData = payload.new as any;
                            const author = allUsers.find(u => u.id === newMessageData.author_id);
                            if (author) {
                                const newMessage: ChatMessage = { ...newMessageData, author };
                                setChatMessages(current => current.some(m => m.id === newMessage.id) ? current : [...current, newMessage]);
                            }
                        }
                        if (payload.eventType === 'UPDATE') {
                            const updatedMessageData = payload.new as any;
                            setChatMessages(current => current.map(m => {
                                if (m.id === updatedMessageData.id) {
                                    return { ...m, ...updatedMessageData };
                                }
                                return m;
                            }));
                        }
                        if (payload.eventType === 'DELETE') {
                            setChatMessages(current => current.filter(m => m.id !== payload.old.id));
                        }
                    })
                    .subscribe();

                return () => {
                    supabase.removeChannel(channel);
                };
            }
        };

        fetchAndSubscribe();
