    const processMissedNotifications = useCallback(async () => {
        if (!appUser) return;
        const supabase = getSupabase();
        if (!supabase) return;

        try {
            const { data: missedNotifications, error } = await supabase
                .from('global_notifications')
                .select('*')
                .eq('to_email', appUser.email.toLowerCase());

            if (error) throw error;

            if (missedNotifications && missedNotifications.length > 0) {
                missedNotifications.forEach(notif => handleReceivedGlobalNotification(notif, true));

                const idsToDelete = missedNotifications.map(n => n.id);
                await supabase.from('global_notifications').delete().in('id', idsToDelete);
            } 
        } catch (err) {
            console.error("[Sync] Error fetching missed notifications:", err);
            addNotification({
                title: "Sync Error",
                message: "Could not sync notifications received while you were offline.",
                type: 'warning',
                persist: false,
            });
        }
    }, [appUser, handleReceivedGlobalNotification, addNotification]);

    useEffect(() => {
        const supabase = getSupabase();
        if (!supabase || !appUser) return;

        const channel = supabase.channel(`global-notifications-for-${appUser.id}`)
          .on('postgres_changes', {
            event: 'INSERT',
            schema: 'public',
            table: 'global_notifications',
            filter: `to_email=eq.${appUser.email.toLowerCase()}`
          }, async (payload) => {
            handleReceivedGlobalNotification(payload.new, false); 
            await supabase!.from('global_notifications').delete().eq('id', payload.new.id);
          })
          .subscribe((status, err) => {
              if (status === 'SUBSCRIBED') {
                  processMissedNotifications();
              }
              if (status === 'CHANNEL_ERROR') {
                  console.warn('[Realtime] Connection issue:', err);
                  // Silenced aggressive notification to prevent spam
              }
              if (status === 'TIMED_OUT') {
                  console.warn('[Realtime] Connection timed out. Reconnecting...');
              }
          });

        return () => {
            supabase.removeChannel(channel);
        };
    }, [appUser, handleReceivedGlobalNotification, processMissedNotifications, addNotification]);

