  const handleSignup = async (name: string, email: string, password: string): Promise<string | void> => {
    let userCredential; 
    isSigningUpRef.current = true;
    try {
        userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const { user } = userCredential;

        await updateProfile(user, { displayName: name });

        const newUserForDb = {
            id: user.uid, 
            name: name,
            email: email,
            avatar: `https://i.pravatar.cc/150?u=${email}`,
            role: 'user',
            writeup_access: 'none',
            status: 'unverified',
            created_at: new Date().toISOString(),
            admin_verified: false,
            welcome_email_sent: false,
        };

        const addedUser = await addUser(newUserForDb as User);

        if (!addedUser) {
            console.error("Failed to create user record in database. Rolling back Firebase user.");
            await deleteFirebaseUser(user);
            return 'Failed to create your profile. Please try again.';
        }

        await sendEmailVerification(user);

        setVerificationEmail(email);
        addNotification({
            title: 'Verification Required',
            message: `A verification link has been sent to ${email}. Please verify and log in.`,
            type: 'info', duration: 8000
        });

        setShowLanding(false);
        setIs404(false);
        setAuthPage('auth');
        setAuthInitialMode('verify');

    } catch (error: any) {
        console.error("Signup process failed:", error);
        if (error.code === 'auth/email-already-in-use') {
            return 'An account with this email already exists.';
        }

        if (userCredential && userCredential.user) {
            try {
                await deleteFirebaseUser(userCredential.user);
                console.log("Cleaned up orphaned Firebase user due to a subsequent error during signup.");
            } catch (cleanupError: any) {
                if (cleanupError.code !== 'auth/user-not-found') {
                  console.error("Failed to clean up orphaned Firebase user:", cleanupError);
                }
            }
        }

        return 'An unknown error occurred during sign-up. Your registration was not completed.';
    } finally {
        isSigningUpRef.current = false;
    }
  };

  const handleSocialLogin = async (providerName: 'google' | 'github'): Promise<string | void> => {
    const provider = providerName === 'google' ? googleProvider : githubProvider;
    // Fix: Set flag BEFORE auth call to catch the listener event
    sessionStorage.setItem('isNewLogin', 'true'); 
    try {
      await signInWithPopup(auth, provider);
    } catch (error: any) {
      // Fix: Clean up if failed
      sessionStorage.removeItem('isNewLogin');
      console.error("Social login error:", error);
      if (error.code === 'auth/popup-closed-by-user') {
        return;
      }
      if (error.code === 'auth/account-exists-with-different-credential') {
        return `An account already exists with this email address. Please sign in using the method you originally used.`;
      }
      return 'An error occurred during social sign-in. Please try again.';
    }
  };

  const handleResendVerification = async () => {
    if (auth.currentUser) {
      if(resendCooldown > 0) return;
      setIsResending(true);
      try {
        await sendEmailVerification(auth.currentUser);
        addNotification({
          title: 'Verification Resent',
          message: `A new verification link has been sent to ${auth.currentUser.email}.`,
          type: 'info'
        });
        setResendCooldown(60);
      } catch (error: any) {
        if (error.code === 'auth/too-many-requests') {
          addNotification({ title: 'Slow Down!', message: 'You have requested this too many times. Please wait before trying again.', type: 'warning' });
          setResendCooldown(60);
        } else {
          addNotification({ title: 'Error', message: 'Failed to resend verification email.', type: 'error' });
        }
      } finally {
        setIsResending(false);
      }
    } else {
        addNotification({ title: 'Login Required', message: 'Please log in to resend the verification email.', type: 'info' });
        setAuthInitialMode('signin');
    }
  };

  const checkVerificationStatus = async () => {
    const currentUser = auth.currentUser;

    if (!currentUser) {
        addNotification({ title: 'Login Required', message: 'Please log in to verify your status.', type: 'info' });
        setAuthInitialMode('signin');
        return;
    }

    await currentUser.reload();
    const freshUser = auth.currentUser;
    if (freshUser?.emailVerified) {
        setVerificationCheckCount(0);
        setFirebaseUser(freshUser); 
        addNotification({
            title: 'Email Verified!',
            message: 'Your email has been verified. You can now log in.',
            type: 'success'
        });
        signOut(auth).then(() => {
            setShowLanding(false);
            setIs404(false);
            setAuthPage('auth');
            setAuthInitialMode('signin');
        });
    } else {
        const messageIndex = verificationCheckCount % wittyVerificationMessages.length;
        addNotification({
            title: 'Not Quite...',
            message: wittyVerificationMessages[messageIndex],
            type: 'warning'
        });
        setVerificationCheckCount(c => c + 1);
    }
  }


  const handleLogout = async () => {
    if (!appUser) return;
    logActivity('logged out');
    signOut(auth).catch(error => {
        console.error("Error during sign out:", error);
    });
  };

  const handlePostDeletionAnimation = useCallback(() => {
    setShowDeletionAnimation(false);

    setTimeout(() => {
        addNotification({
            title: 'Account Deleted',
            message: 'Your account has been successfully and permanently deleted.',
            type: 'success',
            duration: 10000
        });
    }, 500);
  }, [addNotification]);

  const handleDeleteAccount = useCallback(async (): Promise<string | void> => {
    if (!appUser) return "You must be logged in to delete your account.";
    if (!firebaseUser) return "Please log in with your password to perform this action.";

    try {
        const supabaseSuccess = await deleteSupabaseUser(appUser.id);
        if (!supabaseSuccess) {
            throw new Error("Could not delete your user data from our records.");
        }

        await deleteFirebaseUser(firebaseUser);

        setShowDeletionAnimation(true);

    } catch (error: any) {
        console.error("Error deleting account:", error);
        if (error.code === 'auth/requires-recent-login') {
            addNotification({
                title: 'Re-authentication Required',
                message: 'This is a sensitive action. Please log out and log back in before deleting your account.',
                type: 'warning',
                duration: 8000
            });
            return 'Please log out and log back in to proceed.';
        }
        addNotification({ title: 'Deletion Failed', message: error.message || 'Could not delete your account. Please try again.', type: 'error' });
        return 'An unknown error occurred during account deletion.';
    }
  }, [appUser, firebaseUser, addNotification]);

  const handleVerifyPassword = useCallback(async (password: string): Promise<boolean> => {
    const user = auth.currentUser;
    if (!user || !user.email) {
      addNotification({ title: 'Error', message: 'User not found. Please log in again.', type: 'error' });
      return false;
    }

    try {
      const credential = EmailAuthProvider.credential(user.email, password);
      await reauthenticateWithCredential(user, credential);
      return true;
    } catch (error: any) {
      console.error("Password verification failed:", error);
      if (error.code === 'auth/wrong-password' || error.code === 'auth/invalid-credential') {
        return false;
      }
      addNotification({ title: 'Verification Error', message: 'An unexpected error occurred. Please try again later.', type: 'error' });
      return false;
    }
  }, [addNotification]);

  const handleEmailChange = useCallback(async (newEmail: string): Promise<string | void> => {
    const user = auth.currentUser;
    if (!user) {
      return "You are not logged in.";
    }

    try {
      await verifyBeforeUpdateEmail(user, newEmail);
      addNotification({
        title: 'Verification Link Sent',
        message: `A link to verify your new email address has been sent to ${newEmail}.`,
        type: 'success',
        duration: 8000
      });
    } catch (error: any) {
      console.error("Error sending email verification link:", error);
      if (error.code === 'auth/email-already-in-use') {
        return 'This email address is already in use by another account.';
      }
      if (error.code === 'auth/invalid-email') {
        return 'The email address is not valid.';
      }
      if (error.code === 'auth/requires-recent-login') {
        return 'This is a sensitive action. Please log out and log back in before changing your email.';
      }
      return 'An unexpected error occurred. Please try again.';
    }
  }, [addNotification]);

  const handleContactAdmin = useCallback((from: GlobalNotification['from'], message: string) => {
    const admins = allUsersRef.current.filter(u => u.role === 'admin');
    const notifs: GlobalNotification[] = admins.map(admin => ({
        id: crypto.randomUUID(),
        to: admin.email,
        from,
        type: 'contact_admin_request',
        message,
        targetId: from.email,
        targetType: 'user',
    }));
    sendGlobalNotifications(notifs);
}, []);

  // --- Post Handlers with Optimistic UI ---
  const handleSavePost = useCallback(async (postData: Post | Omit<Post, 'id' | 'created_at' | 'author' | 'comments' | 'liked_by'>, type: 'writeup' | 'blog'): Promise<Post | null> => {
    if (!appUser) return null;
    const stateUpdater = type === 'writeup' ? setWriteups : setBlogPosts;
    const isNew = !('id' in postData);

    const tempId = `temp-${Date.now()}`;
    let optimisticPost: Post;

    if (isNew) {
        optimisticPost = {
            ...(postData as Omit<Post, 'id' | 'created_at' | 'author' | 'comments' | 'liked_by'>),
            id: tempId,
            created_at: new Date().toISOString(),
            author: appUser,
            comments: [],
            liked_by: [],
        };
        stateUpdater(current => [optimisticPost, ...current]);
    } else {
        optimisticPost = postData as Post;
        stateUpdater(current => current.map(p => p.id === optimisticPost.id ? optimisticPost : p));
    }

    try {
        let savedPost: Post | null = null;
        if (isNew) {
            const { id, created_at, ...postToInsert } = optimisticPost;
            savedPost = await addPost(postToInsert);
        } else {
            savedPost = await updatePost(optimisticPost.id, optimisticPost);
        }

        if (savedPost) {
             if (isNew) {
                stateUpdater(current => {
                    // If the real post arrived via subscription already, just remove the temp one
                    if (current.some(p => p.id === savedPost!.id)) {
                        return current.filter(p => p.id !== tempId);
                    }
                    return current.map(p => p.id === tempId ? savedPost! : p);
                });
                logActivity(`created a new ${type}`, `"${savedPost.title}"`);
             } else {
                logActivity(`updated a ${type}`, `"${savedPost.title}"`);
             }
             return savedPost;
        } else {
            throw new Error("Failed to save post to database.");
        }
    } catch (e) {
        console.error("Error saving post:", e);
        addNotification({ title: 'Error', message: 'Could not save post. Reverting changes.', type: 'error' });
        if (isNew) {
            stateUpdater(current => current.filter(p => p.id !== tempId));
        } else {
            // For failed updates, the real-time listener will eventually correct the state.
        }
        return null;
    }
  }, [appUser, addNotification, logActivity]);

  const handleDeletePost = useCallback(async (postId: string, type: 'writeup' | 'blog') => {
      const stateUpdater = type === 'writeup' ? setWriteups : setBlogPosts;
      let originalPosts: Post[] = [];
      let deletedPostTitle: string | undefined;

      stateUpdater(current => {
          originalPosts = [...current];
          const postToDelete = current.find(p => p.id === postId);
          deletedPostTitle = postToDelete?.title;
          return current.filter(p => p.id !== postId);
      });

      const success = await deletePost(postId);
      if (!success) {
          stateUpdater(originalPosts);
          addNotification({ title: 'Error', message: 'Failed to delete post.', type: 'error' });
      } else {
          addNotification({ title: 'Success!', message: 'The post has been deleted.', type: 'success' });
          if (deletedPostTitle) {
            logActivity(`deleted a ${type}`, `"${deletedPostTitle}"`);
          }
      }
  }, [addNotification, logActivity]);

  const handleLikePost = useCallback(async (post: Post, liker: User) => {
      const stateUpdater = post.type === 'writeup' ? setWriteups : setBlogPosts;
      const originalPost = (post.type === 'writeup' ? writeups : blogPosts).find(p => p.id === post.id)!;
      const hasLiked = originalPost.liked_by.includes(liker.id);

      const optimisticPost: Post = {
          ...originalPost,
          liked_by: hasLiked
              ? originalPost.liked_by.filter(id => id !== liker.id)
              : [...originalPost.liked_by, liker.id],
      };

      stateUpdater(current => current.map(p => p.id === post.id ? optimisticPost : p));

      try {
          const updatedPost = await likePost(post.id, originalPost, liker.id);
          if (updatedPost) {
              if (!hasLiked) {
                createPostNotification(updatedPost, liker, 'like_post', `${liker.name} liked your post: "${updatedPost.title}"`);
                logActivity(`liked a ${post.type}`, `"${post.title}"`);
              }
          }
      } catch (e) {
          stateUpdater(current => current.map(p => p.id === post.id ? originalPost : p));
          addNotification({ title: 'Error', message: 'Could not update like.', type: 'error' });
      }
  }, [writeups, blogPosts, createPostNotification, logActivity, addNotification]);

  const handleAddCommentToPost = useCallback(async (post: Post, commentText: string) => {
    if (!appUser) return;
    const stateUpdater = post.type === 'writeup' ? setWriteups : setBlogPosts;
    const originalPost = (post.type === 'writeup' ? writeups : blogPosts).find(p => p.id === post.id)!;

    const newComment: Comment = {
        id: `temp-${Date.now()}`,
        author: appUser,
        text: commentText,
        created_at: new Date().toISOString(),
    };

    const optimisticPost: Post = {
        ...originalPost,
        comments: [newComment, ...(originalPost.comments || [])],
    };

    stateUpdater(current => current.map(p => p.id === post.id ? optimisticPost : p));

    try {
        const dbComment = { ...newComment, id: crypto.randomUUID() };
        const updatedPost = await addCommentToPost(post.id, originalPost, dbComment);

        if (updatedPost) {
            createPostNotification(updatedPost, appUser, 'comment_post', `${appUser.name} commented on your post: "${updatedPost.title}"`);
            logActivity(`commented on a ${post.type}`, `"${post.title}"`);
        } else {
            throw new Error("Failed to add comment to database.");
        }
    } catch (e) {
        stateUpdater(current => current.map(p => p.id === post.id ? originalPost : p));
        addNotification({ title: 'Error', message: 'Could not add comment.', type: 'error' });
    }
  }, [appUser, writeups, blogPosts, createPostNotification, logActivity, addNotification]);

  const handleDeleteCommentFromPost = useCallback(async (post: Post, commentId: string) => {
    if (!appUser) return;
    const stateUpdater = post.type === 'writeup' ? setWriteups : setBlogPosts;
    const originalPosts = post.type === 'writeup' ? writeups : blogPosts;
    const originalPost = originalPosts.find(p => p.id === post.id)!;

    const optimisticPost: Post = {
        ...originalPost,
        comments: originalPost.comments.filter(c => c.id !== commentId),
    };

    stateUpdater(current => current.map(p => p.id === post.id ? optimisticPost : p));

    try {
        const updatedPost = await updatePost(post.id, { comments: optimisticPost.comments });

        if (updatedPost) {
            logActivity(`deleted a comment on a ${post.type}`, `"${post.title}"`);
        } else {
            throw new Error("Failed to delete comment from database.");
        }
    } catch (e) {
        stateUpdater(current => current.map(p => p.id === post.id ? originalPost : p));
        addNotification({ title: 'Error', message: 'Could not delete comment.', type: 'error' });
    }
  }, [appUser, writeups, blogPosts, logActivity, addNotification]);

  const backgroundStyle: React.CSSProperties = {
    backgroundImage: (authPage || showLanding || is404) ? 'none' : `url(${selectedBackground})`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
  };

  if (isInitialAuthLoading || isDbLoading) {
    const message = isInitialAuthLoading ? "Securing your session..." : "Loading workspace...";
    return (
        <div style={backgroundStyle} className={`min-h-screen font-sans flex items-center justify-center`}>
            <div className="text-center">
                <MicrochipLoader />
                <h1 className="text-xl font-bold text-slate-800 dark:text-white mt-4">{message}</h1>
                <p className="text-sm text-slate-500 dark:text-slate-300 mt-2">Please wait a moment.</p>
            </div>
        </div>
    );
  }

  const handleNavigateToAuth = (mode: 'signin' | 'signup') => {
      setShowLanding(false);
      setAuthPage('auth');
      setAuthInitialMode(mode);
      // Fix: Update URL to reflect auth state so listeners don't redirect to landing on error
      window.location.hash = '#/auth';
  };

  const handleBackToLanding = () => {
      setShowLanding(true);
      setAuthPage(null);
      window.location.hash = "#/";
  };

  // Render 404 page if explicitly set
  if (is404) {
      return (
        <div style={backgroundStyle} className={`min-h-screen font-sans`}>
            <NotFoundPage />
        </div>
      );
  }

  return (
    <NotificationProvider value={notificationContextValue}>
      <div style={backgroundStyle} className={`${(authPage === null && appUser) ? 'h-[100dvh] overflow-hidden' : 'min-h-screen'} font-sans relative`}>
        {appUser && !showLanding && <AnimatedBackground />}
        <NotificationContainer />

        {/* EXCLUSIVE RENDER: If Welcome Animation is running (ref) or showing (state), render Animation */}
        {(showWelcomeAnimation || isWelcomeAnimationRunning.current) && userForWelcome ? (
             <WelcomeAnimation onComplete={handleWelcomeAnimationEnd} username={userForWelcome.name.split(' ')[0]} />
        ) : (
            <>
                {/* Dashboard - Render if logged in */}
                {appUser && !showLanding && (
                  <main className="h-full w-full overflow-hidden">
                    <DashboardPage 
                      user={appUser} 
                      allUsers={allUsers}
                      writeups={writeups}
                      blogPosts={blogPosts}
                      setAllUsers={setAllUsers} 
                      onLogout={handleLogout} 
                      onSendFriendRequest={handleSendFriendRequest} 
                      onAcceptFriendRequest={handleAcceptFriendRequest}
                      onRejectFriendRequest={handleRejectFriendRequest}
                      onRemoveFriend={handleRemoveFriend} 
                      onProfileUpdate={handleProfileUpdate}
                      onSavePost={handleSavePost}
                      onDeletePost={handleDeletePost}
                      onLikePost={handleLikePost}
                      onAddCommentToPost={handleAddCommentToPost}
                      onDeleteCommentFromPost={handleDeleteCommentFromPost}
                      onRequestWriteupAccess={handleRequestWriteupAccess}
                      onApproveWriteupAccess={handleApproveWriteupAccess}
                      onRejectWriteupAccess={handleRejectWriteupAccess}
                      onDeleteAccount={handleDeleteAccount}
                      onVerifyPassword={handleVerifyPassword}
                      onEmailChange={handleEmailChange}
                      isSyncingProfile={isSyncingProfile}
                    />
                  </main>
                )}

                {/* Landing Page - Render if no user and landing state is active AND login is NOT in progress */}
                {!appUser && showLanding && !authPage && !isPerformingLoginRef.current && !userForWelcome && (
                    <LandingPage 
                        onGetStarted={() => handleNavigateToAuth('signup')}
                        onSignIn={() => handleNavigateToAuth('signin')}
                        onContactAdmin={handleContactAdmin}
                        allUsers={allUsers}
                    />
                )}

                {/* Auth Page - Render if no user and authPage state is active */}
                {authPage && !appUser && !userForWelcome && (
                  <div ref={authBodyRef} className="fixed inset-0 z-50 transition-opacity duration-300 auth-body">
                    <AuthPage 
                      isExiting={isAuthExiting}
                      initialMode={authInitialMode}
                      onLogin={handleLogin}
                      onSignup={handleSignup}
                      onSocialLogin={handleSocialLogin}
                      onForgotPassword={handleForgotPassword}
                      email={verificationEmail || emailFor2FA}
                      onResend={handleResendVerification}
                      onGoToLogin={() => { 
                        if (auth.currentUser) {
                          signOut(auth); 
                        }
                        setAuthInitialMode('signin');
                      }}
                      isResending={isResending}
                      resendCooldown={resendCooldown}
                      onCheckStatus={checkVerificationStatus}
                      onResendMagicLink={handleResendMagicLink}
                      onVerify2FACode={handleVerify2FACode}
                      isVerifying2FACode={isVerifying2FA}
                      twoFACodeError={twoFAError}
                      twoFAAttemptFailed={twoFAAttemptFailed}
                      onClear2FAError={() => setTwoFAError(null)}
                      onContactAdmin={handleContactAdmin}
                      onBackToHome={handleBackToLanding} 
                    />
                  </div>
                )}
            </>
        )}

        {showDeletionAnimation && (
            <DeletionAnimation onAnimationEnd={handlePostDeletionAnimation} />
        )}
      </div>
    </NotificationProvider>
  );
};

