              const postTitle = postTitleMatch ? postTitleMatch[1] : 'your post';
              const finalMessage = `${fromUser.name || 'Someone'} liked your post: "${postTitle}"`;
              addNotification({ ...commonProps, title: 'Your Post was Liked', message: finalMessage, type: 'info', sourceType: 'like_post' });
              break;
          case 'comment_post':
              addNotification({ ...commonProps, title: 'New Comment on Your Post', message: notif.message || 'Someone commented on your post.', type: 'info', sourceType: 'comment_post' });
              break;
          case 'writeup_access_rejected':
              addNotification({
                  ...commonProps,
                  title: 'Access Request Update',
                  message: notif.message || 'Your request for writeup access has been rejected.',
                  type: 'warning',
                  sourceType: 'writeup_access_rejected',
              });
              break;
          case 'friend_request_rejected':
              addNotification({
                  ...commonProps,
                  title: 'Friend Request Rejected',
                  message: notif.message || `${fromUser.name} rejected your friend request.`,
                  type: 'warning',
                  sourceType: 'friend_request_rejected',
              });
