          case 'contact_admin_request':
              if (appUserRef.current?.role === 'admin') {
                  addNotification({
                      ...commonProps,
                      title: 'New Contact Request',
                      message: notif.message || `${fromUser.name} contacted you.`,
                      type: 'info',
