  const handleSendFriendRequest = useCallback(async (fromUser: User, toUserEmail: string) => {
    const toUser = allUsersRef.current.find(u => u.email === toUserEmail);
    if (!toUser) {
        addNotification({ title: 'Error', message: 'User not found.', type: 'error' });
        return;
    }

    const alreadyFriends = toUser.friends?.includes(fromUser.email);
    const requestExists = toUser.friend_requests?.includes(fromUser.email);

    if (alreadyFriends || requestExists) {
      addNotification({ title: 'Request Not Sent', message: 'You are already friends or a request is pending.', type: 'info' });
      return;
    }

    try {
        const updatedFriendRequests = [...(toUser.friend_requests || []), fromUser.email];
        const updatedToUser = await updateUser(toUserEmail, { friend_requests: updatedFriendRequests });

        if (!updatedToUser) {
            throw new Error("Failed to update user's friend requests in the database.");
        }

        setAllUsers(prevUsers => prevUsers.map(u => 
          u.email === toUserEmail ? updatedToUser : u
        ));

        const newGlobalNotif: GlobalNotification = {
          id: `${Date.now()}-${fromUser.email}-${toUserEmail}`,
          to: toUserEmail,
          from: { email: fromUser.email, name: fromUser.name, avatar: fromUser.avatar, role: fromUser.role },
          type: 'friend_request',
          message: `${fromUser.name} wants to be your friend.`,
          targetId: fromUser.email,
          targetType: 'user',
        };

        const notificationSent = await sendGlobalNotifications([newGlobalNotif]);
        if (!notificationSent) {
            const revertedFriendRequests = (updatedToUser.friend_requests || []).filter(email => email !== fromUser.email);
            await updateUser(toUserEmail, { friend_requests: revertedFriendRequests });
            setAllUsers(prevUsers => prevUsers.map(u => u.email === toUserEmail ? { ...updatedToUser, friend_requests: revertedFriendRequests } : u));
            throw new Error("Failed to send notification. The request has been cancelled.");
        }

        addNotification({ title: 'Friend Request Sent!', message: `Your request to ${toUser.name} has been sent.`, type: 'success' });
        logActivity('sent a friend request to', toUser.name);

    } catch (error) {
        console.error("Failed to send friend request:", error);
        addNotification({ title: 'Error', message: (error as Error).message || 'Could not send friend request. Please try again.', type: 'error' });
    }
  }, [addNotification, logActivity, setAllUsers]);


  const handleAcceptFriendRequest = useCallback(async (requestor: { email: string; name: string }) => {
    if (!appUser) return;
    const { email: requestorEmail, name: requestorName } = requestor;

    const notificationToDelete = notificationsRef.current.find(n => 
        n.sourceType === 'friend_request' && n.fromUser?.email === requestorEmail
    );

    try {
        const requestorUser = allUsersRef.current.find(u => u.email === requestorEmail);
        if (!requestorUser) throw new Error("Requesting user not found in local state.");

        const newFriendRequests = (appUser.friend_requests || []).filter(email => email !== requestorEmail);
        const newFriends = [...(appUser.friends || []), requestorEmail];
        const newRequestorFriends = [...(requestorUser.friends || []), appUser.email];

        const [currentUserUpdate, requestorUpdate] = await Promise.all([
            updateUser(appUser.email, { friends: newFriends, friend_requests: newFriendRequests }),
            updateUser(requestorEmail, { friends: newRequestorFriends }),
        ]);

        if (!currentUserUpdate || !requestorUpdate) {
            throw new Error("Failed to update user records in the database.");
        }

        const newGlobalNotif: GlobalNotification = {
            id: `${Date.now()}-friend-accept-${appUser.email}-${requestorEmail}`,
            to: requestorEmail,
            from: { email: appUser.email, name: appUser.name, avatar: appUser.avatar, role: appUser.role },
            type: 'friend_request_accepted',
            message: `${appUser.name} accepted your friend request.`,
            targetId: appUser.email,
            targetType: 'user',
        };
        sendGlobalNotifications([newGlobalNotif]);

        if (notificationToDelete) {
            const success = await deleteNotificationFromDb(notificationToDelete.id); 
            if (!success) {
                console.warn(`Friend added, but failed to soft-delete notification ${notificationToDelete.id}.`);
                addNotification({ title: 'Sync Warning', message: 'Friend added, but notification could not be removed automatically.', type: 'warning' });
            }
        }

        setAppUser(currentUserUpdate);
        setAllUsers(currentAllUsers => currentAllUsers.map(u => {
            if (u.email === appUser.email) return currentUserUpdate;
            if (u.email === requestorEmail) return requestorUpdate;
            return u;
        }));

        addNotification({ title: 'Friend Request Accepted', message: `You are now friends with ${requestorName}.`, type: 'success' });
        logActivity('accepted a friend request from', requestorName);

    } catch (error) {
        console.error("Failed to accept friend request:", error);
        addNotification({ title: 'Update Error', message: 'Failed to accept friend request. Please try again.', type: 'error' });
    }
}, [appUser, addNotification, logActivity]);

